// DATA SOURCE — the single seam between the UI and where data actually lives.
//
// The app is a READ-ONLY, student-centric progress lookup. It reads either:
//   • LIVE-ish: real data pulled from Google Classroom into classroomData.json
//     (generated by spike/pull-classroom-data.mjs), when that file has students, OR
//   • MOCK: the built-in mock Classroom data, otherwise (default / demo).
// The UI never changes — it only knows this contract:
//
//   getStudents() -> Promise<Student[]>
//     Student = { id, name, grade, counts: { done, fic, notdone } }
//
//   getStudentProgress(id) -> Promise<Progress | null>
//     Progress = { id, name, grade, counts, items: Item[] }
//     Item = { id, subject, topic, title, status, posted, due, fixBy, material, given }

import * as classroom from './mockClassroom'
import live from './classroomData.json'

// Use pulled Classroom data when present; otherwise fall back to mock.
const students = Array.isArray(live?.students) ? live.students : []
const USE_LIVE = students.length > 0

function counts(items = []) {
  return {
    done: items.filter((i) => i.status === 'done').length,
    fic: items.filter((i) => i.status === 'fic').length,
    notdone: items.filter((i) => i.status === 'notdone').length,
  }
}

export async function getStudents() {
  if (!USE_LIVE) return classroom.getStudents()
  return students.map((s) => ({ id: s.id, name: s.name, grade: s.grade, counts: counts(s.items) }))
}

export async function getStudentProgress(id) {
  if (!USE_LIVE) return classroom.getStudentProgress(id)
  const s = students.find((x) => x.id === id)
  if (!s) return null
  return { id: s.id, name: s.name, grade: s.grade, counts: counts(s.items), items: s.items }
}

export const { TOPIC_ORDER, SUBJECT_ORDER } = classroom
